public static class Pipeline
{
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
            return 0L;

        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(16)
        {
            SingleReader = true,
            SingleWriter = true
        });

        var producer = Task.Run(async () =>
        {
            try
            {
                for (int i = 0; i < count; i++)
                {
                    await channel.Writer.WriteAsync(i).ConfigureAwait(false);
                }
            }
            finally
            {
                channel.Writer.Complete();
            }
        });

        long sum = 0L;
        await foreach (var item in channel.Reader.ReadAllAsync().ConfigureAwait(false))
        {
            sum += item;
        }

        await producer.ConfigureAwait(false);
        return sum;
    }
}

