public static class Stats
{
    public static (double Mean, double Max) MeanAndMax(IEnumerable<double> values)
    {
        ArgumentNullException.ThrowIfNull(values);

        using var enumerator = values.GetEnumerator();

        if (!enumerator.MoveNext())
            throw new ArgumentException("Sequence must contain at least one element.", nameof(values));

        double sum = enumerator.Current;
        double max = enumerator.Current;
        long count = 1;

        while (enumerator.MoveNext())
        {
            double current = enumerator.Current;
            sum += current;
            if (current > max)
                max = current;
            count++;
        }

        return (sum / count, max);
    }
}

