    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;

        while (!csv.IsEmpty)
        {
            int comma = csv.IndexOf(',');
            ReadOnlySpan<char> token;

            if (comma < 0)
            {
                token = csv;
                csv = ReadOnlySpan<char>.Empty;
            }
            else
            {
                token = csv[..comma];
                csv = csv[(comma + 1)..];
            }

            token = token.Trim();

            if (!token.IsEmpty)
            {
                sum += int.Parse(token, NumberStyles.Integer, CultureInfo.InvariantCulture);
            }
        }

        return sum;
    }
}

