    {
        int sum = 0;
        while (!csv.IsEmpty)
        {
            int comma = csv.IndexOf(',');
            ReadOnlySpan<char> segment;
            if (comma < 0)
            {
                segment = csv;
                csv = ReadOnlySpan<char>.Empty;
            }
            else
            {
                segment = csv.Slice(0, comma);
                csv = csv.Slice(comma + 1);
            }

            segment = segment.Trim();
            if (!segment.IsEmpty)
            {
